import { cn } from '@/utils/cn';
import { cva, VariantProps } from 'class-variance-authority';
import { Component, Show } from 'solid-js';
import { ChatBubbleProps } from './chatBubble.type';

const variants = cva('', {
  variants: {
    color: {
      default: '',
      neutral: 'chat-bubble-neutral',
      primary: 'chat-bubble-primary',
      secondary: 'chat-bubble-secondary',
      accent: 'chat-bubble-accent',
      info: 'chat-bubble-info',
      success: 'chat-bubble-success',
      warning: 'chat-bubble-warning',
      error: 'chat-bubble-error',
    },
    align: {
      start: 'chat-start',
      end: 'chat-end',
    },
  },
});
export type ChatBubbleVariantsProps = VariantProps<typeof variants>;
export const ChatBubble: Component<ChatBubbleProps> = props => {
  return (
    <>
      <div class={cn('chat', variants({ align: props.align }))}>
        <Show when={props.avatar}>
          <div class={cn('chat-image', props.class?.avatar)}>{props.avatar as Element}</div>
        </Show>
        <Show when={props.header}>
          <div class={cn('chat-header', props.class?.header)}>{props.header as Element}</div>
        </Show>
        <Show when={props.bubble}>
          <div class={cn('chat-bubble', variants({ color: props.color }), props.class?.bubble)}>
            {props.bubble as Element}
          </div>
        </Show>
        <Show when={props.footer}>
          <div class={cn('chat-footer', props.class?.footer)}>{props.bubble as Element}</div>
        </Show>
      </div>
    </>
  );
};
